86,0.19538561,0.04419177,0.06316952,0.02604077,-0.01362151,-0.05142180,-0.01376245,0.02133248,-0.02554531,-0.00269259,0.08548495,-0.02434928,0.02699431,0.04208376,0.02258835,-0.04360226,0.01731915,-0.03802078,-0.05520537,0.01624323,-0.00353235,0.03086032,0.05763721,-0.04383308,-0.02321112,-0.05321161,0.01461658,-0.04407688,0.00022649,0.00890929,-0.00275672,-0.00686930,0.01961479,0.01528148,-0.01816279,0.06464764,-0.02983213,-0.02300436,-0.00475362,0.03592935,-0.01601316,0.00963716,0.02003982]',E'Smart Entity Loader\n\nThe Entity Loader intelligently uses join for 1-1 and data loader for 1-N relations,\neliminating the N+1 problem even when performing nested queries.\n```rust\n// join paths:\n// user -> profile\n// user -> post\n//         post -> post_tag -> tag\nlet smart_user = user::Entity::load()\n    .filter_by_id(42) // shorthand for .filter(user::COLUMN.id.eq(42))\n    .with(profile::Entity) // 1-1 uses join\n    .with((post::Entity, tag::Entity)) // 1-N uses data loader\n    .one(db)\n    .await?\n    .unwrap();\n\n// 3 queries are executed under the hood:\n// 1. SELECT FROM user JOIN profile WHERE id = $\n// 2. SELECT FROM post WHERE user_id IN (..)\n// 3. SELECT FROM tag JOIN post_tag WHERE post_id IN (..)\n\nsmart_user','{"source": "sea-orm", "version": "1.0", "language": "rust", "title": "\ud83d\udc1a SeaORM", "section_title": "README", "url": "https://github.com/SeaQL/sea-orm/blob/master/README.md", "topics": "seaorm,rust,orm,async,README", "categories": "database,orm,rust,async"}');
