0.11576819,0.15753564,0.04932848,0.05184096,0.07159388,0.07583441,-0.03359880,0.06692350,0.08756879,-0.02478236,-0.00321954,0.02185244,-0.00034851,0.03096909,0.00531976,0.03828736,0.01806803,0.00079528,-0.04315108,-0.06958362,0.02083252,-0.01231299,0.02544700,0.05182584,-0.04153775,-0.02327720,-0.06000738,-0.02057647,0.01187080,-0.00642178,0.01359117,-0.04708710,0.03251144,0.08550320,0.02411507,-0.02386140,0.00925776,-0.02421694,0.01835715,0.03277827,-0.00570365,0.00480076,0.03812062,0.00937308]',E'Ergonomic Raw SQL\n\nLet SeaORM handle 95% of your transactional queries.\nFor the remaining cases that are too complex to express,\nSeaORM still offers convenient support for writing raw SQL.\n```rust\nlet user = Item { name: "Bob" }; // nested parameter access\nlet ids = [2, 3, 4]; // expanded by the `..` operator\n\nlet user: Option<user::Model> = user::Entity::find()\n    .from_raw_sql(raw_sql!(\n        Sqlite,\n        r#"SELECT "id", "name" FROM "user"\n           WHERE "name" LIKE {user.name}\n           AND "id" in ({..ids})\n        "#\n    ))\n    .one(db)\n    .await?;\n```','{"source": "sea-orm", "version": "1.0", "language": "rust", "title": "\ud83d\udc1a SeaORM", "section_title": "README", "url": "https://github.com/SeaQL/sea-orm/blob/master/README.md", "topics": "seaorm,rust,orm,async,README", "categories": "database,orm,rust,async"}');
