7416,0.02625355,0.05555942,0.01387926,-0.03170815,-0.05835884,-0.00037822,0.04759705,0.01057073,0.01680834,0.11046924,-0.00194736,0.05773519,0.03460300,0.04698301,-0.01442619,0.02374101,-0.06678239,-0.06602488,0.01266833,-0.03327861,0.01584891,0.05464760,-0.03621788,-0.00339547,0.00977884,0.00933337,0.02495972,0.06287409,-0.01287003,-0.02591424,-0.01333085,0.03662019,-0.03364111,-0.02933092,0.00614939,-0.06423812,0.05842227,0.03606023,0.00634176,-0.00833684,0.04080378,-0.03267193]',E'Nested Select\n\nPartial models prevent overfetching by letting you querying only the fields\nyou need; it also makes writing deeply nested relational queries simple.\n```rust\nuse sea_orm::DerivePartialModel;\n\n#[derive(DerivePartialModel)]\n#[sea_orm(entity = "cake::Entity")]\nstruct CakeWithFruit {\n    id: i32,\n    name: String,\n    #[sea_orm(nested)]\n    fruit: Option<fruit::Model>, // this can be a regular or another partial model\n}\n\nlet cakes: Vec<CakeWithFruit> = Cake::find()\n    .left_join(fruit::Entity) // no need to specify join condition\n    .into_partial_model() // only the columns in the partial model will be selected\n    .all(db)\n    .await?;\n```','{"source": "sea-orm", "version": "1.0", "language": "rust", "title": "\ud83d\udc1a SeaORM", "section_title": "README", "url": "https://github.com/SeaQL/sea-orm/blob/master/README.md", "topics": "seaorm,rust,orm,async,README", "categories": "database,orm,rust,async"}');
