2448389,0.16817775,0.02190784,0.04268745,0.01960574,0.02990354,-0.03082367,0.00253671,0.04082801,-0.00466872,0.01479883,0.08768060,0.03738080,0.03202213,0.00153575,0.02750498,0.01551793,-0.03234266,-0.03586306,-0.08035056,0.03397182,-0.05696959,0.02250048,0.03475177,-0.04243258,-0.00236491,0.02961741,-0.04045686,-0.00576058,0.01296655,-0.04959387,-0.01805769,-0.01682426,0.02569900,-0.00034861,-0.03492206,0.03228264,-0.02472744,0.03748354,0.07377429,0.02564492,-0.01241186,0.01686525,-0.01883426]',E'Update\n\nActiveModel avoids race conditions by updating only the fields you''ve changed,\nnever overwriting untouched columns.\nYou can also craft complex bulk update queries with a fluent query building API.\n```rust\nuse sea_orm::sea_query::{Expr, Value};\n\nlet pear: Option<fruit::Model> = Fruit::find_by_id(1).one(db).await?;\nlet mut pear: fruit::ActiveModel = pear.unwrap().into();\n\npear.name = Set("Sweet pear".to_owned()); // update value of a single field\n\n// update one: only changed columns will be updated\nlet pear: fruit::Model = pear.update(db).await?;\n\n// update many: UPDATE "fruit" SET "cake_id" = "cake_id" + 2\n//               WHERE "fruit"."name" LIKE ''%Apple%''\nFruit::update_many()\n    .col_expr(fruit::COLUMN.cake_id, fruit::COLUMN.cake_id.add(2))\n    .filter(fruit::COLUMN.name.contains("Apple"))\n    .exec(db)\n    .await?;\n```','{"source": "sea-orm", "version": "1.0", "language": "rust", "title": "\ud83d\udc1a SeaORM", "section_title": "README", "url": "https://github.com/SeaQL/sea-orm/blob/master/README.md", "topics": "seaorm,rust,orm,async,README", "categories": "database,orm,rust,async"}');
