5,0.04109070,-0.01330579,0.03333280,0.00614086,-0.02182530,0.02105537,0.03483585,-0.01892674,-0.01567045,0.04664796,0.04062489,0.01592880,-0.07944947,0.01380064,-0.03293197,-0.00645246,-0.08983194,-0.05789021,0.04001837,-0.01973233,-0.02697797,0.06936309,-0.06055839,-0.01245214,0.02414188,-0.03845096,-0.00619340,0.04632128,-0.07154088,-0.04335180,0.00669422,0.04157478,0.02276463,-0.01235133,0.05974090,-0.04379934,-0.02089801,0.07521590,0.05586598,-0.04457283,0.05026013,0.00857874]',E'Delete\n\nThe same ActiveModel API consistent with insert and update.\n```rust\n// delete one: Active Record style\nlet orange: Option<fruit::Model> = Fruit::find_by_id(1).one(db).await?;\nlet orange: fruit::Model = orange.unwrap();\norange.delete(db).await?;\n\n// delete one: repository style\nlet orange = fruit::ActiveModel {\n    id: Set(2),\n    ..Default::default()\n};\nfruit::Entity::delete(orange).exec(db).await?;\n\n// delete many: DELETE FROM "fruit" WHERE "fruit"."name" LIKE ''%Orange%''\nfruit::Entity::delete_many()\n    .filter(fruit::COLUMN.name.contains("Orange"))\n    .exec(db)\n    .await?;\n\n```','{"source": "sea-orm", "version": "1.0", "language": "rust", "title": "\ud83d\udc1a SeaORM", "section_title": "README", "url": "https://github.com/SeaQL/sea-orm/blob/master/README.md", "topics": "seaorm,rust,orm,async,README", "categories": "database,orm,rust,async"}');
