434570,0.14745878,0.05989774,0.01712805,0.01170533,0.03691171,-0.01001623,0.06933954,0.09634958,-0.00463365,-0.00741249,0.06450910,-0.00813495,0.04221217,0.02405621,0.00518532,0.02313007,-0.01050182,0.00851220,-0.08399475,0.01532451,-0.02000310,0.01226840,0.03639428,-0.02914388,0.00146948,-0.07728820,0.03998430,0.01970063,0.04427132,0.02190048,-0.02728155,0.00844717,0.07084020,-0.00451176,-0.00727106,0.00852444,-0.01953231,0.11815364,0.01344969,-0.02233725,0.02590859,0.08182947,-0.01981949]',E'Raw SQL Query\n\nThe `raw_sql!` macro is like the `format!` macro but without the risk of SQL injection.\nIt supports nested parameter interpolation, array and tuple expansion, and even repeating group,\noffering great flexibility in crafting complex queries.\n\n```rust\n#[derive(FromQueryResult)]\nstruct CakeWithBakery {\n    name: String,\n    #[sea_orm(nested)]\n    bakery: Option<Bakery>,\n}\n\n#[derive(FromQueryResult)]\nstruct Bakery {\n    #[sea_orm(alias = "bakery_name")]\n    name: String,\n}\n\nlet cake_ids = [2, 3, 4]; // expanded by the `..` operator\n\n// can use many APIs with raw SQL, including nested select\nlet cake: Option<CakeWithBakery> = CakeWithBakery::find_by_statement(raw_sql!(\n    Sqlite,\n    r#"SELECT "cake"."name", "bakery"."name" AS "bakery_name"\n       FROM "cake"\n       LEFT JOIN "bakery" ON "cake"."bakery_id" = "bakery"."id"\n       WHERE "cake"."id" IN ({..cake_ids})"#\n))\n.one(db)\n.await?;\n```','{"source": "sea-orm", "version": "1.0", "language": "rust", "title": "\ud83d\udc1a SeaORM", "section_title": "README", "url": "https://github.com/SeaQL/sea-orm/blob/master/README.md", "topics": "seaorm,rust,orm,async,README", "categories": "database,orm,rust,async"}');
